import{_ as e,o as r,c as a,a2 as o}from"./chunks/framework.CQMe4Urg.js";const P=JSON.parse('{"title":"第 3 章 · Prompt Engineering","description":"","frontmatter":{},"headers":[],"relativePath":"03-prompt-engineering/index.md","filePath":"03-prompt-engineering/index.md","lastUpdated":1776333512000}'),n={name:"03-prompt-engineering/index.md"};function i(p,t,d,h,m,l){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="第-3-章-·-prompt-engineering" tabindex="-1">第 3 章 · Prompt Engineering <a class="header-anchor" href="#第-3-章-·-prompt-engineering" aria-label="Permalink to &quot;第 3 章 · Prompt Engineering&quot;">​</a></h1><p>Prompt 是你与 LLM 之间的&quot;编程语言&quot;。同一个模型，不同 Prompt 的效果可以天差地别。在 Agent 开发中，Prompt 的质量直接决定了 Agent 的能力上限。</p><h2 id="本章三层结构" tabindex="-1">本章三层结构 <a class="header-anchor" href="#本章三层结构" aria-label="Permalink to &quot;本章三层结构&quot;">​</a></h2><h3 id="初级-prompt-基础" tabindex="-1">初级：Prompt 基础 <a class="header-anchor" href="#初级-prompt-基础" aria-label="Permalink to &quot;初级：Prompt 基础&quot;">​</a></h3><p>掌握 Prompt 的核心原则（清晰、具体、结构化），学会 System Prompt 设计，能用 Few-shot 示例引导模型。学完能写出稳定可靠的 Prompt。</p><h3 id="中级-高级推理技巧" tabindex="-1">中级：高级推理技巧 <a class="header-anchor" href="#中级-高级推理技巧" aria-label="Permalink to &quot;中级：高级推理技巧&quot;">​</a></h3><p>深入 Chain-of-Thought、Tree-of-Thought 等推理技巧，掌握结构化输出（JSON/XML），学会动态 Few-shot 和 Self-Consistency。学完能设计复杂的推理 Prompt。</p><h3 id="高级-prompt-工程化" tabindex="-1">高级：Prompt 工程化 <a class="header-anchor" href="#高级-prompt-工程化" aria-label="Permalink to &quot;高级：Prompt 工程化&quot;">​</a></h3><p>建立 Prompt 版本管理和 A/B 测试体系，掌握系统化的 Prompt 调试方法，了解自动化 Prompt 优化和 DSPy。学完能建立完整的 Prompt 工程化体系。</p><h2 id="学完能做到" tabindex="-1">学完能做到 <a class="header-anchor" href="#学完能做到" aria-label="Permalink to &quot;学完能做到&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>学完你能</th></tr></thead><tbody><tr><td>初级</td><td>写出稳定的 Prompt，设计 System Prompt，使用 Few-shot</td></tr><tr><td>中级</td><td>设计复杂推理 Prompt，实现结构化输出，处理解析失败</td></tr><tr><td>高级</td><td>建立 Prompt 版本管理，做 A/B 测试，系统化调试优化</td></tr></tbody></table><h2 id="前置要求" tabindex="-1">前置要求 <a class="header-anchor" href="#前置要求" aria-label="Permalink to &quot;前置要求&quot;">​</a></h2><ul><li>能调用 LLM API（Claude 或 OpenAI）</li><li>了解 Python 基础语法</li></ul>',13)])])}const c=e(n,[["render",i]]);export{P as __pageData,c as default};
